parameters.jsCode:
const aiItems = $input.all();
const locationItems = $('Build Location Payload').all();
let allGrants = [];

aiItems.forEach((aiItem, index) => {
  const locData = locationItems[index]?.json || {};
  const grant = locData.grant || {};
  const orgId = locData.org_id;
  const location_filter_reason = locData.location_filter_reason || '';

  if (!orgId) return;

  const aiText = aiItem.json?.output?.[0]?.content?.[0]?.text || '';

  let classification = { grant_type: grant.grant_type || 'federal', grant_state: grant.grant_state || null, summary: aiText, relevant: true, reason: '' };
  try {
    const cleaned = aiText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    classification = JSON.parse(cleaned);
  } catch (e) {}

  if (classification.relevant === false) return;

  const description = classification.summary || grant.description || '';

  const descriptionHtml = '<div><h3>Grant Opportunity</h3>' +
    '<p><strong>Source:</strong> ' + (grant.source || '') + '</p>' +
    '<p><strong>Agency:</strong> ' + (grant.agency || '') + '</p>' +
    '<p><strong>Type:</strong> ' + (classification.grant_type || grant.grant_type || 'unknown') + '</p>' +
    (classification.grant_state || grant.grant_state ? '<p><strong>State:</strong> ' + (classification.grant_state || grant.grant_state) + '</p>' : '') +
    '<p><strong>Award Range:</strong> $' + (grant.awardFloor || 0) + ' - $' + (grant.awardCeiling || 0) + '</p>' +
    '<p><strong>Open Date:</strong> ' + (grant.openDate || '') + '</p>' +
    '<p><strong>Deadline:</strong> ' + (grant.closeDate || '') + '</p>' +
    '<hr><h4>Description:</h4>' +
    '<p>' + description + '</p>' +
    '<p><em>Relevance: ' + (classification.reason || 'N/A') + '</em></p>' +
    '<hr>' +
    '<p><strong>Matched Keywords:</strong> ' + (Array.isArray(grant.matchedKeywords) ? grant.matchedKeywords.join(', ') : (grant.matchedKeywords || '')) + '</p>' +
    '<p><a href="' + (grant.source_url || '') + '">View Original Listing</a></p>' +
    '</div>';

  let deadlineValue = null;
  if (grant.closeDate && grant.closeDate !== 'See listing' && grant.closeDate !== 'Not specified') {
    const parsed = new Date(grant.closeDate);
    if (!isNaN(parsed.getTime())) {
      const yyyy = parsed.getUTCFullYear();
      const mm = String(parsed.getUTCMonth() + 1).padStart(2, '0');
      const dd = String(parsed.getUTCDate()).padStart(2, '0');
      deadlineValue = yyyy + '-' + mm + '-' + dd + 'T00:00:00.000Z';
    } else {
      deadlineValue = grant.closeDate;
    }
  }

  allGrants.push({
    org_id: orgId,
    title: grant.title || '',
    funder_name: grant.agency || null,
    description: description,
    amount: grant.awardCeiling > 0 ? grant.awardCeiling : null,
    deadline: deadlineValue,
    stage: 'discovery',
    source: grant.source || 'Grant Scanner',
    source_id: grant.source_id,
    source_url: grant.source_url,
    metadata: {
      grants_gov_id: grant.id,
      agency_code: grant.agencyCode,
      open_date: grant.openDate,
      award_floor: grant.awardFloor,
      award_ceiling: grant.awardCeiling,
      matched_keywords: grant.matchedKeywords,
      relevance_score: grant.relevanceScore,
      grant_type: classification.grant_type || grant.grant_type || 'unknown',
      grant_state: classification.grant_state || grant.grant_state || null,
      relevance_reason: classification.reason || '',
      location_filter_reason: location_filter_reason,
      priority: 'medium',
      description_html: descriptionHtml
    }
  });
});

if (allGrants.length === 0) {
  return [{ json: { noRelevantGrants: true, message: 'No relevant grants after classification' } }];
}

return allGrants.map(grant => ({ json: grant }));

// Extract grants from Grants.gov search2 API response
const items = $input.all();
const grants = [];

for (const item of items) {
  const response = item.json;

  let oppHits = [];
  if (response.data && response.data.oppHits) {
    oppHits = response.data.oppHits;
  } else if (response.oppHits) {
    oppHits = response.oppHits;
  } else if (Array.isArray(response)) {
    oppHits = response;
  }

  for (const opp of oppHits) {
    if (!opp || !opp.title) continue;

    const oppNum = opp.number || opp.opportunityNumber || 'GG-' + Date.now() + '-' + Math.random().toString(36).substr(2, 5);

    grants.push({
      json: {
        id: opp.id || opp.opportunityId,
        oppNum: oppNum,
        title: opp.title,
        description: opp.synopsis || opp.description || '',
        link: 'https://www.grants.gov/search-results-detail/' + (opp.id || opp.opportunityId),
        openDate: opp.openDate || opp.postedDate || '',
        closeDate: opp.closeDate || 'See listing',
        agency: opp.agency || opp.agencyName || '',
        agencyCode: opp.agencyCode || '',
        category: opp.category || '',
        source: 'Grants.gov',
        awardFloor: parseInt(opp.awardFloor) || 0,
        awardCeiling: parseInt(opp.awardCeiling) || 0,
        status: opp.oppStatus || opp.status || ''
      }
    });
  }
}

return grants.length > 0 ? grants : [{ json: { empty: true, source: 'grants.gov' } }];

// Extract major foundation info from ProPublica single-org lookups
