parameters.jsCode:
// Parse ProPublica 990 data to find grant-making foundations
const items = $input.all();
const foundations = [];

for (const item of items) {
  const response = item.json;

  if (response.error || response.statusCode >= 400) continue;

  // Handle search results
  const orgs = response.organizations || response.results || [];

  for (const org of orgs) {
    const name = (org.name || '').toLowerCase();
    const isFoundation = name.includes('foundation') || 
                         name.includes('trust') || 
                         name.includes('fund') ||
                         name.includes('endowment') ||
                         name.includes('philanthrop');

    if (!isFoundation) continue;

    const oppNum = 'PP-' + (org.ein || Date.now());

    foundations.push({
      json: {
        id: org.ein,
        oppNum: oppNum,
        title: org.name + ' - Potential Grant Source',
        description: 'Tax-exempt organization in ' + (org.city || 'Pennsylvania') + ', ' + (org.state || 'PA') + '. Review their 990 for grant-making activity.',
        link: 'https://projects.propublica.org/nonprofits/organizations/' + org.ein,
        openDate: new Date().toISOString().split('T')[0],
        closeDate: 'Ongoing - Contact directly',
        agency: org.name,
        agencyCode: '',
        category: 'Foundation',
        source: 'ProPublica 990',
        awardFloor: 0,
        awardCeiling: 0,
        status: 'active'
      }
    });
  }
}

return foundations.length > 0 ? foundations : [{ json: { empty: true, source: 'propublica' } }];

// Parse Philanthropy News Digest RSS for RFPs
const items = $input.all();
const rfps = [];

for (const item of items) {
  const rss = item.json.data || item.json.body || item.json;

  if (typeof rss !== 'string') continue;

  // Extract items from RSS
  const itemMatches = rss.match(/<item>([\s\S]*?)<\/item>/gi) || [];

  for (const itemXml of itemMatches) {
    const titleMatch = itemXml.match(/<title>([^<]+)<\/title>/);
    const linkMatch = itemXml.match(/<link>([^<]+)<\/link>/);
    const descMatch = itemXml.match(/<description>([^<]+)<\/description>/);
    const pubDateMatch = itemXml.match(/<pubDate>([^<]+)<\/pubDate>/);

    if (!titleMatch) continue;

    const title = titleMatch[1].replace(/<!\[CDATA\[|\]\]>/g, '').trim();
    const link = linkMatch ? linkMatch[1].trim() : '';
    const desc = descMatch ? descMatch[1].replace(/<!\[CDATA\[|\]\]>/g, '').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').trim() : '';
    const pubDate = pubDateMatch ? pubDateMatch[1].trim() : '';

    const oppNum = 'PND-' + Date.now() + '-' + Math.random().toString(36).substr(2, 5);

    rfps.push({
      json: {
        id: oppNum,
        oppNum: oppNum,
        title: title,
        description: desc.substring(0, 500),
        link: link,
        openDate: pubDate || new Date().toISOString().split('T')[0],
        closeDate: 'See RFP details',
        agency: 'Foundation (via PND)',
        agencyCode: '',
        category: 'Foundation RFP',
        source: 'Philanthropy News Digest',
        awardFloor: 0,
        awardCeiling: 0,
        status: 'posted'
      }
    });
  }
}

return rfps.length > 0 ? rfps : [{ json: { empty: true, source: 'pnd-rss' } }];

// Combine all grant sources and remove duplicates/empty items
const allItems = $input.all();
const seen = new Set();
const uniqueGrants = [];

for (const item of allItems) {
  const grant = item.json;

  // Skip empty placeholder items
  if (grant.empty) continue;

  // Create unique key from oppNum or title + source
  const key = grant.oppNum ? grant.oppNum : (grant.title + '-' + grant.source).toLowerCase().replace(/\s+/g, '');

  if (!seen.has(key)) {
    seen.add(key);
    uniqueGrants.push({ json: grant });
  }
}

if (uniqueGrants.length === 0) {
  return [{ json: { noResults: true, message: 'No grants found from any source' } }];
}

return uniqueGrants;

// Filter grants by amount range ($5K - $100K) and add relevance scoring
const items = $input.all();
const qualifiedGrants = [];

if (items.length === 1 && items[0].json.noResults) {
  return items;
}

const keywords = [
  'foster care',
  'foster youth',
  'youth transition',
  'aging out',
  'senior',
  'elderly',
  'aging',
  'older adults',
  'african american',
  'black community',
  'minority',
  'underserved',
  'nonprofit capacity',
  'organizational development',
  'capacity building',
  'pennsylvania',
  'philadelphia',
  'pittsburgh',
  'community development',
  'social services',
  'human services',
  'family services',
  'youth development',
  'community foundation',
  'health and human services',
  'child welfare',
  'independent living',
  'equity',
  'dignity',
  'trauma-informed'
];

for (const item of items) {
  const grant = item.json;

  // For major foundations, always include
  const isMajorFoundation = grant.source && (
    grant.source.includes('Major') || 
    grant.source.includes('Foundation') ||
    grant.source.includes('Yield') ||
    grant.source.includes('Gates') ||
    grant.source.includes('Ford')
  );

  // Filter by amount range for government grants: $5,000 - $100,000
  const meetsAmountCriteria = 
    isMajorFoundation ||
    grant.awardCeiling === 0 || 
    (grant.awardCeiling >= 5000 && grant.awardFloor <= 100000);

  if (!meetsAmountCriteria) continue;

  const searchText = (grant.title + ' ' + grant.description + ' ' + grant.category + ' ' + grant.agency).toLowerCase();

  const matchedKeywords = keywords.filter(function(kw) { return searchText.includes(kw); });

  if (matchedKeywords.length > 0 || isMajorFoundation || grant.source === 'ProPublica 990') {
    qualifiedGrants.push({
      json: {
        id: grant.id,
        oppNum: grant.oppNum,
        title: grant.title,
        description: grant.description,
        link: grant.link,
        openDate: grant.openDate,
        closeDate: grant.closeDate,
        agency: grant.agency,
        agencyCode: grant.agencyCode,
        category: grant.category,
        source: grant.source,
        awardFloor: grant.awardFloor,
        awardCeiling: grant.awardCeiling,
        status: grant.status,
        relevanceScore: matchedKeywords.length + (isMajorFoundation ? 5 : 0),
        matchedKeywords: matchedKeywords.length > 0 ? matchedKeywords : ['foundation']
      }
    });
  }
}

// Sort by relevance and limit to top 25
qualifiedGrants.sort(function(a, b) { return b.json.relevanceScore - a.json.relevanceScore; });
const topGrants = qualifiedGrants.slice(0, 25);

if (topGrants.length === 0) {
  return [{ json: { noResults: true, message: 'No grants matched criteria' } }];
}

return topGrants;

// Input: $input.all() contains items from the HTTP Request node
const items = $input.all();
const grants = [];

for (const item of items) {
    const html = item.json.data; // raw HTML from SAM.gov opportunities page
    if (!html) continue;

    // Regex to extract each table row inside <tbody>
    const rowRegex = /<tr[^>]*>([\s\S]*?)<\/tr>/gi;
    let match;

    while ((match = rowRegex.exec(html)) !== null) {
        const rowHtml = match[1];

        // Extract each <td> content in this row
        const tdRegex = /<td[^>]*>[\s\S]*?<div[^>]*>([\s\S]*?)<\/div>[\s\S]*?<\/td>/gi;
        let tdMatch;
        const tds = [];
        while ((tdMatch = tdRegex.exec(rowHtml)) !== null) {
            let value = tdMatch[1]
                .replace(/<[^>]+>/g, '')  // remove inner HTML tags
                .replace(/&nbsp;/g, ' ')
                .trim();
            tds.push(value);
        }

        // Check if row has at least the expected columns (Close date, Status, Title, Agency, Award min, Award max)
        if (tds.length < 6) continue;

        grants.push({
            json: {
                id: 'SAM-' + tds[2].replace(/\s+/g, '-').substring(0, 50) + '-' + Date.now(),
                title: tds[2] || 'No title',
                description: '', // optional, could add opportunity number from hidden div if needed
                link: 'https://sam.gov' + (tds[2].match(/href="([^"]+)"/) ? tds[2].match(/href="([^"]+)"/)[1] : ''),
                openDate: '', // SAM.gov table doesn’t have open date directly
                closeDate: tds[0] || 'Check site',
                status: tds[1] || 'Unknown',
                agency: tds[3] || 'Unknown',
                awardFloor: tds[4] ? parseFloat(tds[4].replace(/[^0-9.]/g, '')) : 0,
                awardCeiling: tds[5] ? parseFloat(tds[5].replace(/[^0-9.]/g, '')) : 0,
                category: 'Federal Grant',
                source: 'SAM.gov Opportunities',
            }
        });
    }
}

// Return placeholder if no grants found
return grants.length > 0 ? grants : [{ json: { empty: true, source: 'SAM.gov' } }];

// Get all input items
const items = $input.all();

// Flatten all results arrays from each item
const results = items.flatMap(i => {
    // i.json is the actual item object
    const data = i.json.results || []; // ensure results exists
    return data.map(item => ({
        internal_id: item.internal_id,
        award_id: item["Award ID"],
        recipient_name: item["Recipient Name"],
        award_amount: item["Award Amount"],
        base_obligation_date: item["Base Obligation Date"],
        description: item["Description"],
        generated_internal_id: item["generated_internal_id"]
    }));
});

// Return a single node output with all parsed results
return results;

// Get all input items
const items = $input.all();

// Flatten all results arrays from each item
const results = items.flatMap(i => {
    // i.json is the actual item object
    const data = i.json.results || []; // ensure results exists
    return data.map(item => ({
        appl_id: item.appl_id,
        subproject_id: item.subproject_id,
        fiscal_year: item.fiscal_year,
        project_num: item.project_num,
        organization: item.organization?.org_name || null,
        org_city: item.organization?.org_city || null,
        org_state: item.organization?.org_state || null,
        org_country: item.organization?.org_country || null,
        award_type: item.award_type || null,
        activity_code: item.activity_code || null,
        award_amount: item.award_amount,
        is_active: item.is_active,
        principal_investigators: item.principal_investigators?.map(pi => ({
            profile_id: pi.profile_id,
            first_name: pi.first_name,
            last_name: pi.last_name,
            full_name: pi.full_name,
            is_contact_pi: pi.is_contact_pi
        })) || [],
        agency_ic_admin: item.agency_ic_admin?.name || null,
        project_start_date: item.project_start_date,
        project_end_date: item.project_end_date,
        project_title: item.project_title,
        abstract_text: item.abstract_text,
        project_detail_url: item.project_detail_url
    }));
});

// Return a single node output with all parsed results
